import { Injectable } from '@nestjs/common';

import { StylesMvModel } from '@modules/db/styles-mv/models/styles-mv.model';
import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';

@Injectable()
export class StylesMvService {
	constructor(private readonly stylesMvModel: StylesMvModel) {}

	async refreshForStyle({ styleId }: { styleId: number }): Promise<void> {
		return this.stylesMvModel.refreshForStyle({ styleId });
	}

	async getByStyleId({
		styleId,
	}: {
		styleId: IStylesMvBase['style_id'];
	}): Promise<IStylesMvBase | null> {
		return this.stylesMvModel.findByStyleId({ styleId });
	}

	async getByStyleIds({
		styleIds,
		activeOnly = false,
	}: {
		styleIds: IStylesMvBase['style_id'][];
		activeOnly?: boolean;
	}): Promise<IStylesMvBase[]> {
		return this.stylesMvModel.findByStyleIds({ styleIds, activeOnly });
	}

	async getByBrands({
		brands,
		limit,
		categoryId,
	}: {
		brands: string[];
		limit: number;
		categoryId?: number;
	}): Promise<IStylesMvBase[]> {
		return this.stylesMvModel.findByBrands({
			brands,
			limit,
			...(categoryId !== undefined && { categoryId }),
		});
	}

	async getAll({
		limit,
		offset,
	}: {
		limit: number;
		offset: number;
	}): Promise<IStylesMvBase[]> {
		return this.stylesMvModel.findAll({ limit, offset });
	}

	async count(): Promise<number> {
		return this.stylesMvModel.count();
	}
}

