import { Injectable, Logger } from '@nestjs/common';
import { plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { FindByBrandsDto } from '@modules/db/styles-mv/dto/find-by-brands.dto';
import { FindByStyleIdsDto } from '@modules/db/styles-mv/dto/find-by-style-ids.dto';
import { BaseStylesMvDto } from '@modules/db/styles-mv/dto/styles-mv.base.dto';
import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';

import { styleStatus } from '@constants/common.constant';
import {
	KNEX_READ_CONNECTION,
	KNEX_WRITE_CONNECTION,
	TABLE_NAME_STYLES_MV,
} from '@constants/db.constant';

@Injectable()
export class StylesMvModel {
	private readonly logger = new Logger(StylesMvModel.name);
	private readonly tableName = TABLE_NAME_STYLES_MV;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async refreshForStyle({ styleId }: { styleId: number }): Promise<void> {
		try {
			await this.knexWrite.raw('CALL refresh_styles_mv(?)', [styleId]);
			this.logger.debug(`Refreshed styles_mv for style ${styleId}`);
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(
				`Failed to refresh styles_mv for style ${styleId}: ${err.message}`,
			);
			throw err;
		}
	}

	async findByStyleId({
		styleId,
	}: {
		styleId: IStylesMvBase['style_id'];
	}): Promise<IStylesMvBase | null> {
		try {
			const result = await this.knexRead<BaseStylesMvDto>(this.tableName)
				.where({ style_id: styleId })
				.whereNull('deleted_at')
				.first();

			if (!result) {
				this.logger.warn(`No styles_mv record found for styleId ${styleId}`);
				return null;
			}

			this.logger.debug(`Found styles_mv record for styleId ${styleId}`);
			return this.parseStylesMvData({ data: result as unknown as IStylesMvBase });
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(
				`Failed to find styles_mv for styleId ${styleId}: ${err.message}`,
			);
			throw err;
		}
	}

	async findByStyleIds({
		styleIds,
		activeOnly = false,
	}: {
		styleIds: IStylesMvBase['style_id'][];
		activeOnly?: boolean;
	}): Promise<IStylesMvBase[]> {
		if (styleIds.length === 0) {
			return [];
		}

		const dto = plainToInstance(FindByStyleIdsDto, { styleIds, activeOnly });
		const errors = await validate(dto);
		if (errors.length > 0) {
			this.logger.error(
				`Validation failed for findByStyleIds: ${this.formatValidationErrors({ errors })}`,
			);
			throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
		}

		try {
			let query = this.knexRead<BaseStylesMvDto>(this.tableName)
				.whereIn('style_id', styleIds)
				.whereNull('deleted_at');

			if (activeOnly) {
				query = query.where('status', styleStatus.ACTIVE);
			}

			const results = await query;

			this.logger.debug(
				`Found ${results.length} styles_mv records for ${styleIds.length} styleIds${activeOnly ? ' (active only)' : ''}`,
			);
			return results.map((result) =>
				this.parseStylesMvData({ data: result as unknown as IStylesMvBase }),
			);
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(`Failed to find styles_mv by IDs: ${err.message}`);
			throw err;
		}
	}

	async findByBrands({
		brands,
		limit,
		categoryId,
	}: {
		brands: string[];
		limit: number;
		categoryId?: number;
	}): Promise<IStylesMvBase[]> {
		if (brands.length === 0) {
			return [];
		}

		const sanitizedBrands = this.sanitizeBrandNames({ brands });
		if (sanitizedBrands.length === 0) {
			this.logger.warn('All brand names were filtered out during sanitization');
			return [];
		}

		const dto = plainToInstance(FindByBrandsDto, { brands: sanitizedBrands, limit });
		const errors = await validate(dto);
		if (errors.length > 0) {
			this.logger.error(
				`Validation failed for findByBrands: ${this.formatValidationErrors({ errors })}`,
			);
			throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
		}

		try {
			let query = this.knexRead<BaseStylesMvDto>(this.tableName)
				.whereNull('deleted_at')
				.whereIn('brand', sanitizedBrands)
				.where('status', styleStatus.ACTIVE);

			if (categoryId !== undefined) {
				query = query.where('primary_category_id', categoryId);
			}

			const results = await query.limit(limit);

			this.logger.debug(
				`Found ${results.length} styles_mv records for brands: ${brands.join(', ')}`,
			);
			return results.map((result) =>
				this.parseStylesMvData({ data: result as unknown as IStylesMvBase }),
			);
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(`Failed to find styles_mv by brands: ${err.message}`);
			throw err;
		}
	}

	async findAll({
		limit,
		offset,
	}: {
		limit: number;
		offset: number;
	}): Promise<IStylesMvBase[]> {
		try {
			const results = await this.knexRead<BaseStylesMvDto>(this.tableName)
				.whereNull('deleted_at')
				.limit(limit)
				.offset(offset);

			this.logger.debug(`Found ${results.length} styles_mv records`);
			return results.map((result) =>
				this.parseStylesMvData({ data: result as unknown as IStylesMvBase }),
			);
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(`Failed to find all styles_mv: ${err.message}`);
			throw err;
		}
	}

	async count(): Promise<number> {
		try {
			const result = await this.knexRead(this.tableName)
				.whereNull('deleted_at')
				.count('* as count')
				.first();

			return Number(result?.['count'] ?? 0);
		} catch (error: unknown) {
			const err = error instanceof Error ? error : new Error(String(error));
			this.logger.error(`Failed to count styles_mv: ${err.message}`);
			throw err;
		}
	}

	private parseStylesMvData({ data }: { data: IStylesMvBase }): IStylesMvBase {
		return {
			...data,
			sizes: this.parseJsonField({ field: data.sizes }),
			default_unit_prices: this.parseJsonField({ field: data.default_unit_prices }),
			colors: this.parseJsonField({ field: data.colors }),
			condensed_features: this.parseJsonField({ field: data.condensed_features }),
			broad_category_names: this.parseJsonField({ field: data.broad_category_names }),
			sub_category_names: this.parseJsonField({ field: data.sub_category_names }),
			no_minimum: Boolean(data.no_minimum),
		};
	}

	private parseJsonField<T>({ field }: { field: T | string | null }): T | null {
		if (field === null || field === undefined) {
			return null;
		}
		if (typeof field === 'string') {
			try {
				return JSON.parse(field) as T;
			} catch {
				return null;
			}
		}
		return field;
	}

	private sanitizeBrandNames({ brands }: { brands: string[] }): string[] {
		const brandNamePattern = /^[a-zA-Z0-9\s_\-+.'&®™\/]+$/;
		return brands.filter((brand) => {
			if (typeof brand !== 'string' || brand.length === 0 || brand.length > 40) {
				return false;
			}
			return brandNamePattern.test(brand);
		});
	}

	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
		return errors
			.map(
				(error) =>
					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
			)
			.join('; ');
	}
}

